/**
 * Affiliate Server Functions for TanStack Start
 * Functions for searching and managing gym affiliates
 */

import { createServerFn } from "@tanstack/react-start"
import { like } from "drizzle-orm"
import { z } from "zod"
import { getDb } from "@/db"
import type { Affiliate } from "@/db/schemas/affiliates"
import { affiliatesTable } from "@/db/schemas/affiliates"

// ===========================
// Input Schemas
// ===========================

const searchAffiliatesInputSchema = z.object({
  query: z.string(),
})

// ===========================
// Helper Functions
// ===========================

/**
 * Get top affiliates for initial dropdown display
 * Returns up to 25 affiliates ordered alphabetically
 */
async function getTopAffiliates(): Promise<Affiliate[]> {
  const db = getDb()

  const affiliates = await db.query.affiliatesTable.findMany({
    limit: 25,
    orderBy: (table, { asc }) => [asc(table.name)],
  })

  return affiliates
}

// ===========================
// Server Functions
// ===========================

/**
 * Search affiliates by name (for autocomplete)
 * Returns up to 25 matching affiliates
 */
export const searchAffiliatesFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => searchAffiliatesInputSchema.parse(data))
  .handler(async ({ data }) => {
    const db = getDb()

    if (!data.query || data.query.trim().length < 2) {
      // Return top affiliates if no query
      return getTopAffiliates()
    }

    const affiliates = await db.query.affiliatesTable.findMany({
      where: like(affiliatesTable.name, `%${data.query.trim()}%`),
      limit: 25,
      orderBy: (table, { asc }) => [asc(table.name)],
    })

    return affiliates.map((a) => ({
      id: a.id,
      name: a.name,
      verificationStatus: a.verificationStatus,
      location: a.location,
    }))
  })

import type { InferSelectModel } from "drizzle-orm"
import { relations } from "drizzle-orm"
import { index, mysqlTable, varchar } from "drizzle-orm/mysql-core"
import { commonColumns, createAffiliateId } from "./common"
import { teamTable } from "./teams"

// Verification status enum for affiliates
export const affiliateVerificationStatus = [
  "unverified",
  "verified",
  "claimed",
] as const
export type AffiliateVerificationStatus =
  (typeof affiliateVerificationStatus)[number]

// Affiliates Table - Normalized gym/affiliate data
export const affiliatesTable = mysqlTable(
  "affiliates",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createAffiliateId())
      .notNull(),
    name: varchar({ length: 255 }).notNull().unique(), // "CrossFit Downtown"
    // Optional metadata
    location: varchar({ length: 255 }), // "Austin, TX"
    // Verification status: unverified (default), verified (admin verified), claimed (gym owner linked)
    verificationStatus: varchar({
      enum: affiliateVerificationStatus,
      length: 255,
    })
      .default("unverified")
      .notNull(),
    // When claimed, links to the team that owns this affiliate
    ownerTeamId: varchar({ length: 255 }),
  },
  (table) => [
    index("affiliates_name_idx").on(table.name),
    index("affiliates_owner_team_idx").on(table.ownerTeamId),
  ],
)

// Type exports
export type Affiliate = InferSelectModel<typeof affiliatesTable>

// Relations
export const affiliatesRelations = relations(affiliatesTable, ({ one }) => ({
  // The team that owns this affiliate (if claimed)
  ownerTeam: one(teamTable, {
    fields: [affiliatesTable.ownerTeamId],
    references: [teamTable.id],
  }),
}))

          teamName: params.teamName ?? "Unknown Team",
          divisionName: division.label,
        },
      })
    }
  }

  // 16. Update user's affiliate profile if not already set
  if (params.affiliateName && !user.affiliateName) {
    await db
      .update(userTable)
      .set({ affiliateName: params.affiliateName })
      .where(eq(userTable.id, params.userId))
  }

  // 17. Update all user sessions to include new team
  await updateAllSessionsOfUser(params.userId)

  // NOTE: Notification is NOT sent here - callers are responsible for calling
  // notifyRegistrationConfirmed() with appropriate isPaid/amountPaidCents values.
  // - Free registrations: caller sends with isPaid: false
  // - Paid registrations: Stripe webhook sends with isPaid: true after payment

  return {
    registrationId: registration.id,
    teamMemberId,
    athleteTeamId,
  }
}

