    userId,
    roleId: SYSTEM_ROLES_ENUM.MEMBER,
    isSystemRole: true,
    joinedAt: new Date(),
    isActive: true,
  })

  // Update user sessions to include the new team
  await updateAllSessionsOfUser(userId)
}

