  competitionsTable,
  createCommerceProductId,
  createCommercePurchaseId,
  createTeamId,
  createTeamMembershipId,
  createUserId,
  REGISTRATION_STATUS,
  ROLES_ENUM,
  scalingGroupsTable,
  scalingLevelsTable,
  scoresTable,
  TEAM_PERMISSIONS,
  teamInvitationTable,
  teamMembershipTable,
  teamTable,
  userTable,
} from "@/db/schema"
import {
  buildFeeConfig,
  calculateCompetitionFees,
  type FeeBreakdown,
  getRegistrationFee,
  type TeamFeeOverrides,
} from "@/lib/commerce-stubs"
import { CLAIM_TOKEN_EXPIRATION_SECONDS } from "@/constants"
import { getAppUrl } from "@/lib/env"
import {
  addRequestContextAttribute,
  logEntityCreated,
