interface RegisterForCompetitionParams {
  competitionId: string
  userId: string
  divisionId: string
  // Team fields (required for team divisions)
  teamName?: string
  affiliateName?: string
  teammates?: Array<{
    email: string
    firstName?: string
    lastName?: string
    affiliateName?: string
  }>
  /** When true, skip registration window checks (for organizer manual registrations) */
  isOrganizerOverride?: boolean
}

interface RegisterForCompetitionResult {
  registrationId: string
  teamMemberId: string
  athleteTeamId: string | null
}

interface NotifyRegistrationConfirmedParams {
  userId: string
  registrationId: string
  competitionId: string
  isPaid: boolean
  amountPaidCents?: number
  /** Number of pending waivers (queried from DB if not provided) */
  pendingWaiverCount?: number
  /** Whether the user is a placeholder (created by manual registration) */
  isPlaceholderUser?: boolean
  /** Claim token for placeholder users to verify email ownership */
  claimToken?: string
  /** Pre-fetched entities to avoid redundant DB queries (used by workflow) */
  prefetched?: {
    user?: {
      id: string
      email: string | null
      firstName: string | null
    }
    competition?: {
      id: string
      name: string
      slug: string
      startDate: string | Date | null
    }
    registration?: {
      id: string
      divisionId: string | null
      teamName: string | null
      pendingTeammates: string | null
    }
    divisionName?: string
  }
}

